SELECT name, age
FROM lifters
WHERE division = 'M_JEM_AAPF';

SELECT DISTINCT division
FROM lifters
ORDER BY division;

SELECT COUNT(*) AS total_lifters
FROM lifters
WHERE division = 'M_JEM_AAPF';

SELECT division, COUNT(*) AS lifter_count
FROM lifters
GROUP BY division;

SELECT name, division
FROM lifters
ORDER BY division;
